VALUES
  ('social-worker-moex-07930', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列那一項為一個成功社會工作管理者應具備的工作態度（請選擇最適選項）？', '["管理者需以自己利益為管理原則", "管理者必須以機構的利益為前提", "管理者以員工的個人發展為前提", "管理者不必視員工為獨立個體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07931', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '進行組織內員工的水平調動，增進與其他部門的互動和瞭解，此種員工管理與發展方法稱為：', '["工作輪調", "實習指派", "工作分析", "個案研究"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07932', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '經營非營利組織應該結合「方向、管理與督導」三個要素。對從事直接服務組織的中級主管來說，那一個要素最關鍵？', '["方向", "管理", "督導", "診斷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07933', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工招募時，有內部和外部招募，採用員工「內部招募」方式之缺點為：', '["來自員工的新工作刺激較少，缺乏多樣性", "員工就任時，適應工作的時間較短", "能激勵內部員工的工作士氣", "可節省組織招募的成本"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07934', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作的個案分析是屬於員工在職訓練的那一種方法（請選出最適合的）？', '["模擬練習", "理論知識建構", "鼓勵團體參與", "鼓勵案主自我表達"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "a6c91d4ef579", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07935', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「他開始系統化的研究，分解每一項工作，還原其組成，好發現完成每一個工作最有效的方法」，這段 陳述的「他」是指：', '["馬克斯‧韋伯（Max Weber）", "亨利‧甘特（Henry Gantt）", "菲德瑞克‧泰勒（Frederick Taylor）", "亨利‧福特（Henry Ford）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07936', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '科層體系應用在社會工作管理上，依然具有其優點，但不包括以下那一項？', '["可以讓社工人員充分運用其個人判斷或專業自主性，有效地執行工作", "可以提供清楚的命令下達管道，一致性及可預測性的規則", "可以較為公平的分配資源，比較不會造成受服務者得到資源的差別待遇", "可以讓員工知道陞遷時，他們被期待具備何種能力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07937', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當一個球隊在比賽時，有許多熱情的觀眾在場邊加油打氣，球員受到觀眾的激勵，而有非常傑出的表現。 這種效應我們可以稱為：', '["月暈效應", "霍桑效應", "動力效應", "虎克效應"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07938', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於「全面品質管理」（total quality management）的敘述，何者錯誤？', '["愛德華‧戴明（W. Edwards Deming）是這個理念最重要的代表性人物", "是日本式管理Y理論的反射", "品質在缺乏齊一的技術下，將很難界定和建立", "持續改善品質的系統可以被設計及執行"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07939', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '各項管理理論的發展脈絡，依其產生的先後順序，何者正確？', '["古典理論→系統理論→權變理論→人群關係理論", "古典理論→權變理論→系統理論→人群關係理論", "古典理論→人群關係理論→系統理論→權變理論", "古典理論→權變理論→人群關係理論→系統理論"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
